async function api(path,opts={}){const h=opts.body instanceof FormData?{}:{'Content-Type':'application/json'};const r=await fetch(path,Object.assign({headers:h},opts));const d=await r.json().catch(()=>({}));if(!r.ok) throw new Error(d.stderr||d.message||('HTTP '+r.status));return d;}function btn(label,onclick){const b=document.createElement('button');b.textContent=label;b.onclick=onclick;return b;}async function refresh(){const data=await api('/api/bundles');draw(data);}function draw(data){const installedEl=document.getElementById('installed');const bundlesEl=document.getElementById('bundles');const logs=document.getElementById('logs');installedEl.innerHTML='';bundlesEl.innerHTML='';(data.installed||[]).forEach(item=>{const d=document.createElement('div');d.className='row';d.innerHTML=`<strong>${item.name||item.id}</strong> <span>${item.version||''}</span> <span>${item.install_status||''}</span>`;d.appendChild(btn('Remove',async()=>{try{await api('/api/remove',{method:'POST',body:JSON.stringify({app_id:item.id})});await refresh();}catch(e){alert(e.message)}}));if(item.log_path){d.appendChild(btn('View Log',async()=>{try{const log=await api('/api/logs/'+item.id);logs.textContent=log.content;}catch(e){alert(e.message)}}));}installedEl.appendChild(d);});(data.bundles||[]).forEach(item=>{const d=document.createElement('div');d.className='row';d.innerHTML=`<strong>${item.display_name||item.id}</strong> <span>${item.version||''}</span> <span>${item.installed?'installed':'not installed'}</span>`;d.appendChild(btn(item.installed?'Reinstall':'Install',async()=>{try{await api('/api/install',{method:'POST',body:JSON.stringify({bundle_filename:item.filename})});await refresh();}catch(e){alert(e.message)}}));bundlesEl.appendChild(d);});}document.addEventListener('DOMContentLoaded',()=>{document.getElementById('refreshBtn').addEventListener('click',refresh);document.getElementById('uploadForm').addEventListener('submit',async(e)=>{e.preventDefault();const fd=new FormData(e.target);try{await api('/api/upload',{method:'POST',body:fd});e.target.reset();await refresh();}catch(err){alert(err.message)}});refresh();});
